import hashlib

class Block:
 def __init__(self, version, previous_block_hash, merkle_root, timestamp, difficulty_target, nonce, transactions):
 self.version = version
 self.previous_block_hash = previous_block_hash
 self.merkle_root = merkle_root
 self.timestamp = timestamp
 self.difficulty_target = difficulty_target
 self.nonce = nonce
 self.transactions = transactions

 def calculate_block_hash(self):
 header = self.version + self.previous_block_hash + self.merkle_root + self.timestamp + self.difficulty_target + self.nonce
 return hashlib.sha256(hashlib.sha256(header.encode()).digest()).hexdigest()

